
var base_url = window.location.origin;

$(document).on('click','.cart__btn',function() {
    $('.side-cart-items').empty();
    getCart();
});

$(document).on('click','.without_login_cart',function() {
    toastr.error('Please Login First');
});

function getCart() {
    var url = base_url+'/cart';
    $.ajax({
        method: 'GET',
        url: url,
        headers: {
            'X-CSRF-TOKEN': window.csrfToken
        },
        success: function(response) {
            if(response.cart_count == 0){
                $('#cart-count-span').hide();
                $('.main-total-cart').attr('style', 'display: none !important');
                $('.cart-checkout-btn').remove();
                $('.side-cart-items').append('<div class="no_pro_f">No Cart Items Found</div>');
            }else{
                const url = base_url + '/checkout/order';
                $('.main-total-cart').removeAttr('style', 'display: none !important');
                if ($('.checkout-cart').children().length === 0) { 
                    $('.checkout-cart').append('<a href="' + url + '" class="cart-checkout-btn hover-btn">Proceed to Checkout</a>');
                }
            }
            $('#cart-count-span').html('(' + response.cart_count + ' Items)');
            $.each(response.cart_items, function(key, value) {
                if(value.product.type == 'Simple'){
                    let imagePath = '/storage/'+value.product.product_image;
                    let itemTotal = value.product.base_price * value.quantity;
                    let mrp = value.product.base_mrp;
                    let price = value.product.base_price;
                    let percentOff = (mrp > 0 && price > 0) ? Math.round(((mrp - price) / mrp) * 100) : 0;
                    let priceHtml = `
                        <div class="price-wrapper-cart">
                            <span class="percent-off-cart" id="percentage-span-cart">${percentOff}% off</span>
                            <span class="price-mrp-cart" id="product-price-mrp-cart">MRP<del>₹${mrp}</del></span>
                            <span class="price-regular-cart" id="product-price-cart">₹${price}</span>
                        </div>
    `                   ;

                    $('.side-cart-items').append(
                        '<a href="'+base_url+'/product/'+value.product.slug+'" class="anchor-cart-item"><div class="cart-item" data-product-id="' + value.product.product_id + '" data-variant-id="' + value.variation_id + '">' +
                            '<div class="cart-product-img col-md-3">' +
                                '<img src="' + base_url + imagePath + '" alt="">' +
                            '</div>' +
                            '<div class="cart-text col-md-8">' +
                                '<h4>' + value.product.product_name + '</h4>' +
                                '<div class="cart-item-price">'+priceHtml+'</div>' +
                                '<div class="qty-group qty-group_header_cart">' +
                                    '<div class="quantity buttons_added">' +
                                        '<input type="button" value="-" class="cart-minus cart-minus-btn">' +
                                        '<input type="number" name="quantity" value="' + value.quantity + '" class="input-text qty text">' +
                                        '<input type="button" value="+" class="cart-plus cart-plus-btn">' +
                                    '</div>' +
                                    '<div class="cartitem-total-single-product"><strong>Total: ₹' + itemTotal + '</strong></div>' +
                                '</div>' +
                            '</div>' +
                            '<button type="button" class="cart-close-btn"><i class="uil uil-multiply"></i></button>' +
                        '</div></a>'
                    );
                }else{
                    let attributesHtml = '<p><strong>';
                    let attrs = [];
                    
                    $.each(value.variation.variation_attributes, function(attrKey, attrVal) {
                        let attrName = attrVal.attribute.attribute.name;
                        let attrValue = attrVal.attribute.name;
                        attrs.push(attrName + ': ' + attrValue);
                    });
                    
                    attributesHtml += attrs.join(', ') + '</strong></p>';
                    let mrp = value.variation.mrp;
                    let price = value.variation.price;
    
                    let percentOff = (mrp > 0 && price > 0) ? Math.round(((mrp - price) / mrp) * 100) : 0;
    
                    let priceHtml = `
                        <div class="price-wrapper-cart">
                            <span class="percent-off-cart" id="percentage-span-cart">${percentOff}% off</span>
                            <span class="price-mrp-cart" id="product-price-mrp-cart">MRP<del>₹${mrp}</del></span>
                            <span class="price-regular-cart" id="product-price-cart">₹${price}</span>
                        </div>
    `                   ;
                
                    // Use variation image if available, else use product image
                    let imagePath = value.variation.image ? '/storage/' + value.variation.image : value.product.product_image;
                
                    // Calculate item total
                    let itemTotal = value.variation.price * value.quantity;
                
                    $('.side-cart-items').append(
                        '<a href="'+base_url+'/product/'+value.product.slug+'" class="anchor-cart-item"><div class="cart-item" data-product-id="' + value.product.product_id + '" data-variant-id="' + value.variation_id + '">' +
                            '<div class="cart-product-img col-md-3">' +
                                '<img src="' + base_url + imagePath + '" alt="">' +
                            '</div>' +
                            '<div class="cart-text col-md-8">' +
                                '<h4>' + value.product.product_name + '</h4>' +
                                '<div class="cart_attributes_cart">' +
                                    attributesHtml +
                                   
                                '</div>' +
                                '<div class="cart-item-price">'+priceHtml+'</div>' +
                                '<div class="qty-group qty-group_header_cart">' +
                                    '<div class="quantity buttons_added">' +
                                        '<input type="button" value="-" class="cart-minus cart-minus-btn">' +
                                        '<input type="number" name="quantity" value="' + value.quantity + '" class="input-text qty text">' +
                                        '<input type="button" value="+" class="cart-plus cart-plus-btn">' +
                                    '</div>' +
                                    '<div class="cartitem-total"><strong>Total: ₹' + itemTotal + '</strong></div>' +
                                '</div>' +
                            '</div>' +
                            '<button type="button" class="cart-close-btn"><i class="uil uil-multiply"></i></button>' +
                        '</div></a>'
                    );
                    
                }
            });
            
            const rupeeIcon = '₹';
            $('.cart-total-span').html(rupeeIcon + response.cart_total);
        },
        error: function(error) {
            console.log(error);
        }
    });
}

