$(document).on('click','.cart-icon',function(event){
    event.preventDefault();
    const productItem = $(this).closest('.product-item');
    const quantity = productItem.find('input[name="quantity"]').val();
    const variant_id = productItem.data('product-varient');
    const product_id = productItem.data('product-id');
    const url = base_url + '/add/cart';
    // const auth_user = window.authUser;
    // if(!auth_user){
    //     toastr.error('Please Login First');
    //     return false;
    // }
    if(quantity == 0){
        toastr.error('Please Select Quantity');
    }else{
        $.ajax({
            method:'POST',
            url:url,
            headers:{
                'X-CSRF-TOKEN': window.csrfToken
            },
            data:{
                quantity:quantity,
                // variation_id:variant_id,
                product_id:product_id
            },
            success:function(response){	
                if(response.success){
                    $('#cart-count-span').html('(' + response.cart_count + ' Items)');
                    $('.cart-total-span').html('₹'+response.cart_total);
                    if(response.cart_count > 0){
                        if ($('a.cart__btn').find('.cart_count_header').length > 0) {
                            $('.cart_count_header').html(response.cart_count);
                            $('.cart_count_header').show();
                        }else{
                            $('a.cart__btn').append('<ins id=.cart_count_header"></ins>');
                            $('.cart_count_header').html(response.cart_count);
                            $('.cart_count_header').show();
                        }
                    }
                    else{
                        $('.cart_count_header').hide();
                    }
                    toastr.success(response.message);
                }else{
                    toastr.error(response.message);
                }
            },
            error:function(error){
                toastr.error(error.responseJSON.message);
            }
        });
    }
});


$(document).on('click','.cart-close-btn',function(event){
    event.preventDefault();
    const productItem = $(this).closest('.cart-item');
    const variant_id = productItem.data('variant-id');
    const product_id = productItem.data('product-id');
    const anchor = $(this).closest('.anchor-cart-item');
    const summaryItem = $('.order-summary-cart-item .cart-item[data-product-id="'+product_id+'"][data-variant-id="'+variant_id+'"]');
    const url = base_url + '/remove/cart';
    $.ajax({
        method:'POST',
        url:url,
        headers:{
            'X-CSRF-TOKEN': window.csrfToken
        },
        data:{
            variation_id:variant_id,
            product_id:product_id
        },
        success:function(response){	
            if(response.success){
                $('#cart-count-span').html('(' + response.cart_count + ' Items)');
                $('.cart-total-span').html('₹'+response.cart_total);
                if(response.cart_count > 0){
                    if ($('a.cart__btn').find('.cart_count_header').length > 0) {
                        $('.cart_count_header').html(response.cart_count);
                        $('.cart_count_header').show();
                    }else{
                        $('a.cart__btn').append('<ins id=.cart_count_header"></ins>');
                        $('.cart_count_header').html(response.cart_count);
                        $('.cart_count_header').show();
                    }
                }else{
                    $('.cart_count_header').hide();
                }
                $(anchor).remove();
                $(productItem).remove();
                $(summaryItem).remove();
                if ($('.order-summary-cart-item .cart-item').length === 0) {
                    $('.main-total-cart').hide();
                    $('.order-summary-cart-item .pdpt-bg').append('<div class="text-center p-4"><h5>Your cart is empty</h5></div>');
                }
                if ($('.side-cart-items').children().length === 0) {
                    $('.cart-checkout-btn').remove();
                    $('.cart_count_header').hide();
                    $('#cart-count-span').hide();
                    $('.main-total-cart').attr('style', 'display: none !important');
                    $('.side-cart-items').append('<div class="no_pro_f">No Cart Items Found</div>');
                }
                toastr.success(response.message);
            }else{
                toastr.error(response.message);
            }
        },
        error:function(error){
            console.log(error);
        }
    });
});

$(document).on('click', '.cart-minus-btn', function(event) {
    event.preventDefault();
    const productItem = $(this).closest('.cart-item');
    const anchor = $(this).closest('.anchor-cart-item');
    const variant_id = productItem.data('variant-id');
    const product_id = productItem.data('product-id');
    const quantityInput = productItem.find('input[name="quantity"]');
    let quantity_value = parseInt(quantityInput.val(), 10);
    $.ajax({
        method: 'POST',
        url: base_url + '/update/cart/decrease',
        headers: {
            'X-CSRF-TOKEN': window.csrfToken
        },
        data: {
            variation_id: variant_id,
            product_id: product_id,
        },
        success: function(response) {	
            if (response.success) {
                $('#cart-count-span').html('(' + response.cart_count + ' Items)');
                $('.cart-total-span').html('₹'+response.cart_total);
                if(response.cart_count > 0){
                    if ($('a.cart__btn').find('.cart_count_header').length > 0) {
                        $('.cart_count_header').html(response.cart_count);
                        $('.cart_count_header').show();
                    }else{
                        $('a.cart__btn').append('<ins id=.cart_count_header"></ins>');
                        $('.cart_count_header').html(response.cart_count);
                        $('.cart_count_header').show();
                    }
                }else{
                    $('.cart_count_header').hide();
                }
                if(response.product.type == 'Variable'){
                    $('.cartitem-total').html('<strong>Total: ₹' + response.item_total + '</strong>');
                }else{
                    $('.cartitem-total-single-product').html('<strong>Total: ₹' + response.item_total + '</strong>');
                }
                if (quantity_value > 1) {
                    quantityInput.val(quantity_value - 1);
                } else {
                    $(productItem).remove();
                    $(anchor).remove();
                }
                if ($('.side-cart-items').children().length === 0) { 
                    $('.cart-checkout-btn').remove();
                    $('.cart_count_header').hide();
                    $('#cart-count-span').hide();
                    $('.main-total-cart').attr('style', 'display: none !important');
                    $('.side-cart-items').append('<div class="no_pro_f">No Cart Items Found</div>');
                }
                toastr.success(response.message);
            } else {
                toastr.error(response.message);
            }
        },
        error: function(error) {
            console.log(error);
        }
    });
});

$(document).on('click', '.cart-plus-btn', function(event) {
    event.preventDefault();
    const productItem = $(this).closest('.cart-item');
    const anchor = $(this).closest('.anchor-cart-item');
    const variant_id = productItem.data('variant-id');
    const product_id = productItem.data('product-id');
    const quantityInput = productItem.find('input[name="quantity"]');
    let quantity_value = parseInt(quantityInput.val(), 10);
    $.ajax({
        method: 'POST',
        url: base_url + '/update/cart/increase',
        headers: {
            'X-CSRF-TOKEN': window.csrfToken
        },
        data: {
            variation_id: variant_id,
            product_id: product_id,
        },
        success: function(response) {	
            if (response.success) {
                $('#cart-count-span').html('(' + response.cart_count + ' Items)');
                $('.cart-total-span').html('₹'+response.cart_total);
                if(response.cart_count > 0){
                    if ($('a.cart__btn').find('.cart_count_header').length > 0) {
                        $('.cart_count_header').html(response.cart_count);
                        $('.cart_count_header').show();
                    }else{
                        $('a.cart__btn').append('<ins id=.cart_count_header"></ins>');
                        $('.cart_count_header').html(response.cart_count);
                        $('.cart_count_header').show();
                    }
                }
                else{
                    $('.cart_count_header').hide();
                }
                if(response.product.type == 'Variable'){
                    $('.cartitem-total').html('<strong>Total: ₹' + response.item_total + '</strong>');
                }else{
                    $('.cartitem-total-single-product').html('<strong>Total: ₹' + response.item_total + '</strong>');
                }
                if (quantity_value >= 1) {
                    quantityInput.val(quantity_value + 1);
                } else {
                    $('.cart-checkout-btn').remove();
                    $(productItem).remove();
                    $(anchor).remove();
                }
                if ($('.side-cart-items').children().length === 0) { 
                    $('.cart-checkout-btn').remove();
                    $('#cart-count-span').hide();
                    $('.main-total-cart').attr('style', 'display: none !important');
                    $('.side-cart-items').append('<div class="no_pro_f">No Cart Items Found</div>');
                }
                toastr.success(response.message);
            } else {
                toastr.error(response.message);
            }
        },
        error: function(error) {
            console.log(error);
        }
    });
});


